const WARNING_TEMP = 35;
const CRITICAL_TEMP = 45;
const STALE_MS = 30000;
const CRITICAL_HOLD_MS = 10000;
const sourceType = msg.sourceType || "unknown";

function ageMs(ts, nowMs) {
    if (!ts) return null;
    const parsed = Date.parse(ts);
    if (Number.isNaN(parsed)) return null;
    return nowMs - parsed;
}

function normalizePayload(payload) {
    if (typeof payload === "string") {
        try {
            return JSON.parse(payload);
        } catch (error) {
            return payload;
        }
    }
    return payload;
}

function normalizeOps(payload) {
    if (!payload) return null;
    if (typeof payload === "string") {
        return { operationCode: payload };
    }
    if (typeof payload.operationCode === "string") {
        return payload;
    }
    if (typeof payload.code === "string") {
        return { ...payload, operationCode: payload.code };
    }
    return null;
}

function buildControl(topic, power, reason, evaluatedAt) {
    return {
        topic,
        payload: {
            power,
            reason,
            issuedAt: evaluatedAt
        }
    };
}

const nowMs = Date.now();
const evaluatedAt = new Date(nowMs).toISOString();
let normalizedPayload = normalizePayload(msg.payload);
let debugMsg = {
    topic: "sheet2/debug/evaluation",
    payload: {
        evaluatedAt,
        sourceType,
        inputTopic: msg.topic || null,
        payloadType: Array.isArray(normalizedPayload) ? "array" : typeof normalizedPayload
    }
};

if (sourceType === "state-current") {
    if (!normalizedPayload || typeof normalizedPayload !== "object" || Array.isArray(normalizedPayload)) {
        debugMsg.payload.error = "state-current payload is not object";
        node.status({ fill: "red", shape: "ring", text: "state/current payload 오류" });
        return [null, null, null, debugMsg];
    }
    flow.set("sheet2CurrentState", normalizedPayload);
} else if (sourceType === "ops-recommendation") {
    const latestOps = normalizeOps(normalizedPayload);
    if (!latestOps) {
        debugMsg.payload.error = "ops recommendation 형식이 올바르지 않음";
        node.warn("ops recommendation 형식이 올바르지 않습니다.");
        return [null, null, null, debugMsg];
    }
    latestOps.receivedAt = evaluatedAt;
    flow.set("sheet2LatestOps", latestOps);
    debugMsg.payload.storedOpsRecommendation = {
        operationCode: latestOps.operationCode || null,
        message: latestOps.message || null,
        reason: latestOps.reason || null,
        receivedAt: latestOps.receivedAt
    };
    debugMsg.payload.note = "ops recommendation 저장만 수행; 다음 state/current 입력에서 평가";
    node.status({ fill: "blue", shape: "ring", text: "ops 저장" });
    return [null, null, null, debugMsg];
} else {
    debugMsg.payload.error = "unknown sourceType";
    return [null, null, null, debugMsg];
}

const currentState = flow.get("sheet2CurrentState");
const latestOps = flow.get("sheet2LatestOps") || null;

if (!currentState || !currentState.userId || !currentState.roomId) {
    debugMsg.payload.error = "state/current missing in flow context";
    node.status({ fill: "grey", shape: "ring", text: "state/current 대기중" });
    return [null, null, null, debugMsg];
}

const userId = currentState.userId;
const roomId = currentState.roomId;
const temperature = currentState.sensors?.temperature || null;
const vibration = currentState.sensors?.vibration || null;
const conveyorBelt = currentState.actuators?.conveyorBelt || null;
const aircon = currentState.actuators?.aircon || null;

const freshness = {
    temperatureAgeMs: ageMs(temperature?.updatedAt, nowMs),
    vibrationAgeMs: ageMs(vibration?.updatedAt, nowMs),
    conveyorBeltAgeMs: ageMs(conveyorBelt?.updatedAt, nowMs),
    airconAgeMs: ageMs(aircon?.updatedAt, nowMs)
};

const definedAges = Object.values(freshness).filter(v => Number.isFinite(v));
const maxAgeMs = definedAges.length ? Math.max(...definedAges) : null;
const completeness = currentState.completeness || "partial";
const isFresh = completeness === "ready" && maxAgeMs !== null && maxAgeMs <= STALE_MS;

let riskLevel = "unknown";
let ruleState = "hold";
let reason = "state-not-ready";
let criticalSince = flow.get("sheet2CriticalSince") || null;

if (!temperature || typeof temperature.value !== "number") {
    riskLevel = "unknown";
    ruleState = "hold";
    reason = "temperature-missing";
    criticalSince = null;
} else if (!isFresh) {
    riskLevel = "unknown";
    ruleState = "hold";
    reason = completeness !== "ready" ? "partial-state" : "stale-state";
    criticalSince = null;
} else if (temperature.value >= CRITICAL_TEMP) {
    riskLevel = "critical";
    if (!criticalSince) {
        criticalSince = evaluatedAt;
    }
    const criticalHeldMs = nowMs - Date.parse(criticalSince);
    if (latestOps?.operationCode === "recommend-to-stop") {
        ruleState = "stop";
        reason = "ops-stop-on-critical";
    } else if (criticalHeldMs >= CRITICAL_HOLD_MS) {
        ruleState = "stop";
        reason = "critical-held-10s";
    } else {
        ruleState = "cooling";
        reason = "critical-detected";
    }
} else if (temperature.value >= WARNING_TEMP) {
    riskLevel = "warning";
    criticalSince = null;
    if (latestOps?.operationCode === "recommend-to-stop") {
        ruleState = "stop";
        reason = "ops-stop-on-warning";
    } else {
        ruleState = "cooling";
        reason = "warning-detected";
    }
} else {
    riskLevel = "normal";
    criticalSince = null;
    if (latestOps?.operationCode === "recommend-to-monitor") {
        ruleState = "monitor";
        reason = "ops-monitor-on-normal";
    } else {
        ruleState = "normal";
        reason = "temperature-normal";
    }
}

flow.set("sheet2CriticalSince", criticalSince);

const actualConveyorPower = conveyorBelt?.power ?? null;
const actualAirconPower = aircon?.power ?? null;
const ruleResultMsg = {
    topic: `kiot/${userId}/dt/factory/${roomId}/rule/result`,
    payload: {
        userId,
        roomId,
        evaluatedAt,
        riskLevel,
        ruleState,
        reason,
        thresholds: {
            warningTemp: WARNING_TEMP,
            criticalTemp: CRITICAL_TEMP,
            staleMs: STALE_MS,
            criticalHoldMs: CRITICAL_HOLD_MS
        },
        latestOpsRecommendation: latestOps ? {
            operationCode: latestOps.operationCode || null,
            receivedAt: latestOps.receivedAt || null,
            message: latestOps.message || null,
            reason: latestOps.reason || null
        } : null,
        snapshotMeta: {
            completeness,
            latestUpdatedAt: currentState.latestUpdatedAt || null,
            maxAgeMs,
            freshness,
            lastSourceType: currentState.lastSourceType || null,
            criticalSince
        },
        stateSummary: {
            temperature: temperature?.value ?? null,
            vibration: vibration?.value ?? null,
            conveyorPower: actualConveyorPower,
            airconPower: actualAirconPower,
            conveyorOverheatMode: conveyorBelt?.overheatMode ?? null
        }
    }
};

let conveyorMsg = null;
let airconMsg = null;

if ((ruleState === "cooling" || ruleState === "stop") && actualAirconPower !== "on") {
    airconMsg = buildControl(`kiot/${userId}/factory/${roomId}/actuator/aircon/control`, "on", reason, evaluatedAt);
}

if (ruleState === "stop" && actualConveyorPower !== "off") {
    conveyorMsg = buildControl(`kiot/${userId}/factory/${roomId}/actuator/conveyor-belt/control`, "off", reason, evaluatedAt);
}

debugMsg.payload = {
    ...debugMsg.payload,
    userId,
    roomId,
    temperature: temperature?.value ?? null,
    completeness,
    maxAgeMs,
    actualAirconPower,
    actualConveyorPower,
    actualConveyorOverheatMode: conveyorBelt?.overheatMode ?? null,
    latestOpsOperationCode: latestOps?.operationCode || null,
    riskLevel,
    ruleState,
    reason,
    willSendAirconControl: !!airconMsg,
    willSendConveyorControl: !!conveyorMsg
};

const statusColor = ruleState === "stop" ? "red" : ruleState === "cooling" ? "yellow" : ruleState === "hold" ? "grey" : "green";
node.status({ fill: statusColor, shape: "dot", text: `${riskLevel} / ${ruleState}` });

return [ruleResultMsg, conveyorMsg, airconMsg, debugMsg];
